parameters.jsCode:
const items = $input.all();

const filtered = items.filter(item => {
  const data = item.json;
  const hasLinkedIn = data['Person Linkedin Url'] || data['Person Link'];
  return hasLinkedIn;
});

if (filtered.length === 0) {
  return [];
}

return filtered.map(item => ({
  json: {
    first_name: item.json['First Name'] || '',
    linkedin_url: item.json['Person Linkedin Url'] || item.json['Person Link'] || '',
    company_name: item.json['Company'] || '',
    company_domain: item.json['Website'] || '',
    designation: item.json['Title'] || '',
    industry: item.json['Industry'] || ''
  }
}));

