parameters.jsCode:
let rawHtml = $input.item.json.data || '';

// Strip all HTML tags
let text = rawHtml.replace(/<[^>]*>/g, ' ');

// Remove extra whitespace
text = text.replace(/\s+/g, ' ').trim();

// Limit to first 2000 characters only
text = text.substring(0, 2000);

return {
  json: {
    ...$input.item.json,
    website_content: text
  }
};
